// Standalone mode: build config from Sheet rows and prepare minimal report
const config = {};
try {
  const konfigRows = $('Konfig aus Sheet lesen').all();
  for (const row of konfigRows) {
    const key = (row.json['Einstellung'] || row.json['einstellung'] || '').trim();
    const val = (row.json['Wert'] || row.json['wert'] || '').trim();
    if (key) config[key] = val;
  }
} catch (e) {
  // Fallback
}

// Calendar week
const now = new Date();
const year = now.getFullYear();
const jan1 = new Date(year, 0, 1);
const days = Math.floor((now - jan1) / (24 * 60 * 60 * 1000));
const calendarWeek = Math.ceil((days + jan1.getDay() + 1) / 7);

const brandName = config.brand_name || config.project_name || 'SocialPulse';

// In standalone mode, we don't have the full HTML report.
// Create a simple notification email instead.
const htmlReport = `<!DOCTYPE html>
<html lang="de">
<head><meta charset="UTF-8"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;padding:40px;">
<h1 style="color:#1a73e8;">SocialPulse Report | ${brandName} | KW ${calendarWeek}/${year}</h1>
<p style="font-size:16px;color:#4b5563;">Dieser Report wurde im Standalone-Modus ausgeloest.</p>
<p>Fuer den vollstaendigen Report mit Performance-Daten, KI-Analyse und PDF-Anhang starten Sie bitte den Master-Workflow (WF7).</p>
<hr style="border:1px solid #e5e7eb;margin:20px 0;">
<p style="font-size:12px;color:#9ca3af;">Generiert von SocialPulse | ${now.toLocaleDateString('de-DE')}</p>
</body>
</html>`;

return [{
  json: {
    config,
    reportData: {
      reportSubject: 'SocialPulse Report | ' + brandName + ' | KW ' + calendarWeek + '/' + year,
      htmlReport,
      brandName,
      calendarWeek,
      year,
      reportRecipients: (config.report_recipients || '').split(',').map(e => e.trim()).filter(e => e),
      reportCc: (config.report_cc || '').split(',').map(e => e.trim()).filter(e => e),
      pdfGenerated: false,
      standaloneMode: true
    }
  }
}];

// Merge report data from Master or standalone preparation.
const webhookData = $('Webhook Trigger').first().json.body || {};

let reportData;
let config;

if (webhookData.reportData) {
  // Master provided report data
  reportData = webhookData.reportData;
  config = webhookData.config || {};

  // Ensure recipients are parsed
  if (typeof reportData.reportRecipients === 'string') {
    reportData.reportRecipients = reportData.reportRecipients.split(',').map(e => e.trim()).filter(e => e);
  }
  if (typeof reportData.reportCc === 'string') {
    reportData.reportCc = reportData.reportCc.split(',').map(e => e.trim()).filter(e => e);
  }
} else {
  // Standalone mode -- data from Node 4
  try {
    const standaloneResult = $('Standalone-Daten vorbereiten').first().json;
    reportData = standaloneResult.reportData;
    config = standaloneResult.config;
  } catch (e) {
    // Absolute fallback
    reportData = {
      reportSubject: 'SocialPulse Report',
      htmlReport: '<html><body><p>Report konnte nicht geladen werden.</p></body></html>',
      reportRecipients: [],
      reportCc: [],
      pdfGenerated: false,
      standaloneMode: true
    };
    config = {};
  }
}

// Validate recipients
if (!reportData.reportRecipients || reportData.reportRecipients.length === 0) {
  // Try to get from config
  const recipients = (config.report_recipients || '').split(',').map(e => e.trim()).filter(e => e);
  if (recipients.length > 0) {
    reportData.reportRecipients = recipients;
  }
}

return [{
  json: {
    reportSubject: reportData.reportSubject || 'SocialPulse Report',
    htmlReport: reportData.htmlReport || '',
    brandName: reportData.brandName || config.brand_name || 'SocialPulse',
    calendarWeek: reportData.calendarWeek || 0,
    year: reportData.year || new Date().getFullYear(),
    recipients: (reportData.reportRecipients || []).join(', '),
    cc: (reportData.reportCc || []).join(', '),
    pdfAvailable: reportData.pdfGenerated || false,
    standaloneMode: reportData.standaloneMode || false,
    projectName: config.project_name || reportData.projectName || 'unknown'
  }
}];

const data = $input.first().json;

// Validate recipients
if (!data.recipients || data.recipients.trim().length === 0) {
  throw new Error('Keine Empfaenger konfiguriert. Bitte report_recipients in der Konfig-Tab setzen.');
}

// Build subject line
const subject = data.reportSubject || ('SocialPulse Report | ' + data.brandName + ' | KW ' + data.calendarWeek + '/' + data.year);

// Wrap HTML report in email-safe container
let emailHtml = data.htmlReport;

// If standalone, the HTML is already minimal
// If from Master, the full report HTML is email-ready (inline CSS)

// PDF attachment filename
const pdfFilename = 'SocialPulse_Report_' + data.brandName.replace(/[^a-zA-Z0-9]/g, '_') + '_KW' + data.calendarWeek + '_' + data.year + '.pdf';

return [{
  json: {
    sendTo: data.recipients,
    cc: data.cc || '',
    subject,
    emailHtml,
    pdfFilename,
    pdfAvailable: data.pdfAvailable,
    standaloneMode: data.standaloneMode,
    brandName: data.brandName,
    calendarWeek: data.calendarWeek,
    year: data.year,
    projectName: data.projectName
  }
}];

const emailData = $('E-Mail vorbereiten').first().json;
const gmailResult = $('Report versenden').first().json;

const errors = [];

// Check Gmail result
if (gmailResult && gmailResult.error) {
  errors.push({
    source: 'gmail',
    message: 'E-Mail-Versand fehlgeschlagen: ' + JSON.stringify(gmailResult.error)
  });
}

// Check if run log succeeded
try {
  const runLogResult = $('Supabase Run-Log schreiben').first().json;
  if (runLogResult && runLogResult.error) {
    errors.push({
      source: 'run_log',
      message: 'Run-Log konnte nicht geschrieben werden: ' + JSON.stringify(runLogResult.error)
    });
  }
} catch (e) {
  // Run log is non-critical
}

return [{
  json: {
    success: !errors.some(e => e.source === 'gmail'),
    workflow: 'WF6 Report Sender',
    status: errors.length === 0 ? 'success' : (errors.some(e => e.source === 'gmail') ? 'error' : 'partial_success'),
    data: {
      recipients: emailData.sendTo,
      cc: emailData.cc || '',
      subject: emailData.subject,
      pdfAttached: emailData.pdfAvailable,
      standaloneMode: emailData.standaloneMode,
      gmailMessageId: gmailResult?.id || gmailResult?.messageId || null
    },
    errors: errors.length > 0 ? errors : null,
    timestamp: new Date().toISOString()
  }
}];
